import {
  ChangeDetectionStrategy,
  Component,
  inject,
  InjectionToken,
  input,
  model,
  output,
} from "@angular/core";

/** @internal — DI token for the parent accordion controller. */
export const ACCORDION_CONTROLLER = new InjectionToken<AccordionController>(
  "AccordionController",
);

/** @internal — interface implemented by UIAccordion to coordinate single-mode expansion. */
export interface AccordionController {
  notifyExpanded(item: UIAccordionItem): void;
  canCollapse(item: UIAccordionItem): boolean;
}

/**
 * A single collapsible panel inside a `<ui-accordion>`.
 *
 * @example
 * ```html
 * <ui-accordion>
 *   <ui-accordion-item label="Section 1">
 *     Panel content here
 *   </ui-accordion-item>
 * </ui-accordion>
 * ```
 */
@Component({
  selector: "ui-accordion-item",
  standalone: true,
  templateUrl: "./accordion-item.component.html",
  styleUrl: "./accordion-item.component.scss",
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    class: "ui-accordion-item",
    "[class.ui-accordion-item--expanded]": "expanded()",
    "[class.ui-accordion-item--disabled]": "disabled()",
  },
})
export class UIAccordionItem {
  /** Header label text. */
  public readonly label = input.required<string>();

  /** Whether this panel is expanded. Supports two-way binding. */
  public readonly expanded = model(false);

  /** Whether this panel is disabled (cannot toggle). */
  public readonly disabled = input(false);

  /** Accessible label override. */
  public readonly ariaLabel = input<string | undefined>(undefined);

  /** Emitted when the panel is toggled. */
  public readonly expandedChange = output<boolean>();

  /** @internal */
  private readonly accordion = inject(ACCORDION_CONTROLLER, { optional: true });

  /** Toggle the expanded state. */
  public toggle(): void {
    if (this.disabled()) {
      return;
    }
    if (this.expanded()) {
      if (this.accordion?.canCollapse(this) === false) {
        return;
      }
      this.collapse();
    } else {
      this.expand();
    }
  }

  /** Expand the panel. */
  public expand(): void {
    if (this.disabled() || this.expanded()) {
      return;
    }
    this.expanded.set(true);
    this.expandedChange.emit(true);
    this.accordion?.notifyExpanded(this);
  }

  /** Collapse the panel. */
  public collapse(): void {
    if (this.disabled() || !this.expanded()) {
      return;
    }
    this.expanded.set(false);
    this.expandedChange.emit(false);
  }

  /** @internal — keyboard handler for the header. */
  protected onHeaderKeyDown(event: KeyboardEvent): void {
    if (event.key === " " || event.key === "Enter") {
      event.preventDefault();
      this.toggle();
    }
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  contentChild,
  DestroyRef,
  effect,
  ElementRef,
  inject,
  input,
  model,
  output,
  signal,
  TemplateRef,
} from "@angular/core";
import { NgTemplateOutlet } from "@angular/common";

// ── Datasource contract ────────────────────────────────────────────

/**
 * Contract for an autocomplete suggestion provider.
 *
 * `completeFor` receives the current query string and the items that
 * are already selected (so the implementation can exclude them) and
 * returns an array of suggestions.
 */
export interface AutocompleteDatasource<T> {
  completeFor(query: string, selection: readonly T[]): T[];
}

// ── Component ──────────────────────────────────────────────────────

/**
 * Autocomplete / type-ahead component with optional custom item template.
 *
 * Renders a text input that, on every keystroke, queries the supplied
 * {@link AutocompleteDatasource} and shows a popup list of matching items.
 *
 * Consumers project an `<ng-template let-item>` to control how each
 * suggestion is rendered. When no template is provided the component
 * falls back to `String(item)`.
 *
 * Selection is exposed as a two-way `[(value)]` binding carrying the
 * currently selected items.
 *
 * Zero external dependencies — only Angular core + `@angular/common`.
 *
 * @example
 * ```html
 * <ui-autocomplete [datasource]="ds" [(value)]="picked">
 *   <ng-template let-item>
 *     <strong>{{ item.name }}</strong>
 *     <small>{{ item.email }}</small>
 *   </ng-template>
 * </ui-autocomplete>
 * ```
 */
@Component({
  selector: "ui-autocomplete",
  standalone: true,
  imports: [NgTemplateOutlet],
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: "./autocomplete.component.html",
  styleUrl: "./autocomplete.component.scss",
  host: {
    class: "ui-autocomplete",
    "(document:click)": "onDocumentClick($event)",
    "(document:keydown.escape)": "closePopup()",
  },
})
export class UIAutocomplete<T> {
  private static _nextId = 0;

  private readonly elRef = inject(ElementRef<HTMLElement>);
  private readonly destroyRef = inject(DestroyRef);

  // ── Content query ──────────────────────────────────────────

  /** Consumer-projected template for rendering each suggestion item. */
  readonly itemTemplate =
    contentChild<TemplateRef<{ $implicit: T }>>(TemplateRef);

  // ── Inputs ─────────────────────────────────────────────────

  /** Datasource that provides completion suggestions. */
  readonly datasource = input.required<AutocompleteDatasource<T>>();

  /** Whether the control is disabled. */
  readonly disabled = input<boolean>(false);

  /** Placeholder text shown when the input is empty. */
  readonly placeholder = input<string>("Search…");

  /**
   * Accessible label forwarded to the native `<input>` as `aria-label`.
   */
  readonly ariaLabel = input<string>("Autocomplete");

  /**
   * Minimum number of characters before a query is executed.
   * Defaults to `1`.
   */
  readonly minChars = input<number>(1);

  /**
   * Whether to allow multiple selections. When `false` (default),
   * picking an item closes the popup and replaces the value.
   * When `true`, picked items accumulate as chips above the input.
   */
  readonly multiple = input<boolean>(false);

  /**
   * Function that returns a display string for a selected item.
   * Used for chips (multiple mode) and the input value (single mode).
   * Defaults to `String(item)`.
   */
  readonly displayWith = input<(item: T) => string>((item: T) => String(item));

  /**
   * Optional trackBy function for identity comparison.
   * When provided, duplicate-checks use this key.
   */
  readonly trackBy = input<((item: T) => unknown) | undefined>(undefined);

  // ── Two-way value ──────────────────────────────────────────

  /** Currently selected item(s). Two-way bindable via `[(value)]`. */
  readonly value = model<readonly T[]>([]);

  // ── Outputs ────────────────────────────────────────────────

  /** Fired when a suggestion is picked from the popup. */
  readonly itemSelected = output<T>();

  /** Fired when a chip / item is removed in multiple mode. */
  readonly itemRemoved = output<T>();

  // ── Internal state ─────────────────────────────────────────

  /** Raw text in the input. */
  protected readonly query = signal("");

  /** Whether the suggestion popup is visible. */
  protected readonly isOpen = signal(false);

  /** Keyboard-highlighted index inside the suggestions list. */
  protected readonly activeIndex = signal(-1);

  /** The list of current suggestions from the datasource. */
  protected readonly suggestions = computed(() => {
    const q = this.query();
    if (q.length < this.minChars()) return [];
    return this.datasource().completeFor(q, this.value());
  });

  /** Unique listbox id for ARIA. */
  protected readonly listboxId = `ui-ac-listbox-${UIAutocomplete._nextId++}`;

  // ── Input handler ──────────────────────────────────────────

  /** @internal */
  protected onInput(event: Event): void {
    const text = (event.target as HTMLInputElement).value;
    this.query.set(text);
    this.activeIndex.set(-1);
    this.isOpen.set(text.length >= this.minChars());
  }

  // ── Item picking ───────────────────────────────────────────

  /** @internal */
  protected pickItem(item: T): void {
    if (this.multiple()) {
      const tb = this.trackBy();
      const key = tb ? tb(item) : item;
      const alreadySelected = this.value().some(
        (v) => (tb ? tb(v) : v) === key,
      );
      if (!alreadySelected) {
        this.value.set([...this.value(), item]);
      }
    } else {
      this.value.set([item]);
      this.query.set(this.displayWith()(item));
    }
    this.itemSelected.emit(item);
    this.closePopup();
  }

  /** @internal – remove a chip in multiple mode. */
  protected removeItem(item: T): void {
    const tb = this.trackBy();
    const key = tb ? tb(item) : item;
    this.value.set(this.value().filter((v) => (tb ? tb(v) : v) !== key));
    this.itemRemoved.emit(item);
  }

  // ── Keyboard navigation ────────────────────────────────────

  /** @internal */
  protected onKeydown(event: KeyboardEvent): void {
    const items = this.suggestions();
    if (!items.length) return;

    switch (event.key) {
      case "ArrowDown":
        event.preventDefault();
        if (!this.isOpen()) {
          this.isOpen.set(true);
        }
        this.activeIndex.set(
          Math.min(this.activeIndex() + 1, items.length - 1),
        );
        break;

      case "ArrowUp":
        event.preventDefault();
        this.activeIndex.set(Math.max(this.activeIndex() - 1, 0));
        break;

      case "Enter":
        event.preventDefault();
        if (this.activeIndex() >= 0 && this.activeIndex() < items.length) {
          this.pickItem(items[this.activeIndex()]);
        }
        break;

      case "Tab":
        this.closePopup();
        break;
    }
  }

  // ── Popup management ───────────────────────────────────────

  /** @internal */
  protected openPopup(): void {
    if (this.disabled()) return;
    if (this.query().length >= this.minChars()) {
      this.isOpen.set(true);
    }
  }

  /** @internal */
  protected closePopup(): void {
    this.isOpen.set(false);
    this.activeIndex.set(-1);
  }

  /** @internal – close when clicking outside. */
  protected onDocumentClick(event: Event): void {
    if (!this.elRef.nativeElement.contains(event.target as Node)) {
      this.closePopup();
    }
  }

  /** @internal – default fallback string representation. */
  protected itemToString(item: T): string {
    return this.displayWith()(item);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  input,
  output,
} from "@angular/core";

/** A single item in the breadcrumb trail. */
export interface BreadcrumbItem {
  /** Display label. */
  readonly label: string;
  /** Optional route or URL. When absent, the item is non-clickable. */
  readonly url?: string;
  /** Optional icon identifier. */
  readonly icon?: string;
}

/** Visual style for the breadcrumb trail. */
export type BreadcrumbVariant = "link" | "button";

/**
 * A navigation breadcrumb trail.
 *
 * @example
 * ```html
 * <ui-breadcrumb [items]="[
 *   { label: 'Home', url: '/' },
 *   { label: 'Products', url: '/products' },
 *   { label: 'Widget' }
 * ]" />
 * ```
 */
@Component({
  selector: "ui-breadcrumb",
  standalone: true,
  templateUrl: "./breadcrumb.component.html",
  styleUrl: "./breadcrumb.component.scss",
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    class: "ui-breadcrumb",
    "[class.ui-breadcrumb--button]": "variant() === 'button'",
  },
})
export class UIBreadcrumb {
  /** The breadcrumb items to display. */
  public readonly items = input.required<readonly BreadcrumbItem[]>();

  /** Visual style: `link` (default) renders anchors, `button` renders styled buttons with chevron separators. */
  public readonly variant = input<BreadcrumbVariant>("link");

  /** Separator character between items. Only used in `link` variant. */
  public readonly separator = input("/");

  /** Accessible label for the nav element. */
  public readonly ariaLabel = input("Breadcrumb");

  /** Emitted when a breadcrumb item is clicked. */
  public readonly itemClicked = output<BreadcrumbItem>();

  /** @internal — handle click on a breadcrumb item. */
  protected onItemClick(
    event: Event,
    item: BreadcrumbItem,
    isLast: boolean,
  ): void {
    event.preventDefault();
    if (isLast) {
      return;
    }
    this.itemClicked.emit(item);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  input,
  NgZone,
  output,
  signal,
} from "@angular/core";

import { UITableViewColumn } from "../columns/table-column.directive";
import { MIN_COLUMN_WIDTH } from "../table-view.constants";
import type { SelectionMode } from "../../core/selection-model";

export interface SortState {
  key: string;
  direction: "asc" | "desc";
}

export interface ColumnResizeEvent {
  key: string;
  widthPx: number;
}

@Component({
  selector: "ui-table-header",
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  templateUrl: "./table-view-header.component.html",
  styleUrl: "./table-view-header.component.scss",
})
/** @internal */
export class UITableHeader {
  columns = input.required<readonly UITableViewColumn[]>();
  showRowIndexIndicator = input<boolean>(false);
  rowIndexHeaderText = input<string>("#");
  resizable = input<boolean>(false);
  columnWidths = input<Record<string, number>>({});
  selectionMode = input<SelectionMode>("none");
  showSelectionColumn = input<boolean>(true);
  allSelected = input<boolean>(false);
  indeterminate = input<boolean>(false);
  sortChange = output<SortState | null>();
  columnResize = output<ColumnResizeEvent>();
  selectAllChange = output<boolean>();
  sortState = signal<SortState | null>(null);

  protected readonly minColumnWidth = MIN_COLUMN_WIDTH;

  constructor(
    private readonly elRef: ElementRef<HTMLElement>,
    private readonly zone: NgZone,
  ) {}

  protected getColWidth(key: string): number | null {
    return this.columnWidths()[key] ?? null;
  }

  onCellClick(col: UITableViewColumn): void {
    if (!col.sortable()) return;
    const current = this.sortState();
    let next: SortState | null;
    if (current?.key === col.key()) {
      next =
        current.direction === "asc"
          ? { key: col.key(), direction: "desc" }
          : null;
    } else {
      next = { key: col.key(), direction: "asc" };
    }
    this.sortState.set(next);
    this.sortChange.emit(next);
  }

  onResizeStart(event: PointerEvent, colKey: string): void {
    event.preventDefault();
    event.stopPropagation();

    const handle = event.target as HTMLElement;
    const cell = handle.parentElement!;
    const startX = event.clientX;
    const startWidth = cell.getBoundingClientRect().width;
    const root =
      this.elRef.nativeElement.closest(".table-view-root") ??
      this.elRef.nativeElement;

    root.classList.add("tv-resizing");
    handle.setPointerCapture(event.pointerId);

    const onMove = (e: PointerEvent) => {
      const delta = e.clientX - startX;
      const newWidth = Math.max(
        MIN_COLUMN_WIDTH,
        Math.round(startWidth + delta),
      );
      cell.style.width = `${newWidth}px`;
      cell.style.flex = "0 0 auto";
    };

    const onUp = (e: PointerEvent) => {
      handle.releasePointerCapture(e.pointerId);
      handle.removeEventListener("pointermove", onMove);
      handle.removeEventListener("pointerup", onUp);
      root.classList.remove("tv-resizing");

      const finalWidth = Math.max(
        MIN_COLUMN_WIDTH,
        Math.round(cell.getBoundingClientRect().width),
      );
      this.zone.run(() => {
        this.columnResize.emit({ key: colKey, widthPx: finalWidth });
      });
    };

    handle.addEventListener("pointermove", onMove);
    handle.addEventListener("pointerup", onUp);
  }

  onSelectAllToggle(event: Event): void {
    const checked = (event.target as HTMLInputElement).checked;
    this.selectAllChange.emit(checked);
  }
}

import { ChangeDetectionStrategy, Component, signal } from "@angular/core";
import { JsonPipe } from "@angular/common";

import type { Meta, StoryObj } from "@storybook/angular";
import { moduleMetadata } from "@storybook/angular";

import {
  UIAutocomplete,
  type AutocompleteDatasource,
} from "./autocomplete.component";

// ── Helpers ────────────────────────────────────────────────────────

/** A trivial string datasource that does case-insensitive prefix matching. */
class FruitDatasource implements AutocompleteDatasource<string> {
  private readonly fruits = [
    "Apple",
    "Apricot",
    "Avocado",
    "Banana",
    "Blackberry",
    "Blueberry",
    "Cherry",
    "Coconut",
    "Cranberry",
    "Dragonfruit",
    "Fig",
    "Grape",
    "Guava",
    "Kiwi",
    "Lemon",
    "Lime",
    "Lychee",
    "Mango",
    "Melon",
    "Nectarine",
    "Orange",
    "Papaya",
    "Peach",
    "Pear",
    "Pineapple",
    "Plum",
    "Pomegranate",
    "Raspberry",
    "Strawberry",
    "Watermelon",
  ];

  completeFor(query: string, selection: readonly string[]): string[] {
    const lq = query.toLowerCase();
    return this.fruits.filter(
      (f) => f.toLowerCase().includes(lq) && !selection.includes(f),
    );
  }
}

/** A rich-object datasource for the custom-template story. */
interface Contact {
  name: string;
  email: string;
  department: string;
}

const CONTACTS: Contact[] = [
  {
    name: "Alice Johnson",
    email: "alice@example.com",
    department: "Engineering",
  },
  { name: "Bob Smith", email: "bob@example.com", department: "Design" },
  { name: "Carol White", email: "carol@example.com", department: "Marketing" },
  { name: "Dave Brown", email: "dave@example.com", department: "Engineering" },
  { name: "Eve Davis", email: "eve@example.com", department: "Product" },
  {
    name: "Frank Miller",
    email: "frank@example.com",
    department: "Engineering",
  },
  { name: "Grace Lee", email: "grace@example.com", department: "Design" },
  { name: "Hank Wilson", email: "hank@example.com", department: "Marketing" },
];

class ContactDatasource implements AutocompleteDatasource<Contact> {
  completeFor(query: string, selection: readonly Contact[]): Contact[] {
    const lq = query.toLowerCase();
    const selectedEmails = new Set(selection.map((c) => c.email));
    return CONTACTS.filter(
      (c) =>
        !selectedEmails.has(c.email) &&
        (c.name.toLowerCase().includes(lq) ||
          c.email.toLowerCase().includes(lq) ||
          c.department.toLowerCase().includes(lq)),
    );
  }
}

