@Component({
  selector: "ui-mdv-custom-filter-demo",
  standalone: true,
  imports: [UIMasterDetailView, UITextColumn, UIFilter],
  changeDetection: ChangeDetectionStrategy.OnPush,
  styles: [
    `
      :host {
        display: block;
        height: 520px;
