  id: number;
  name: string;
  width: number;
  height: number;
  url: string;
}

const KITTEN_NAMES = [
  "Whiskers",
  "Mittens",
  "Shadow",
  "Pumpkin",
  "Luna",
  "Simba",
  "Mochi",
  "Cleo",
  "Ginger",
  "Felix",
  "Nala",
  "Oliver",
];

function buildKittens(count = 12): Kitten[] {
  return Array.from({ length: count }, (_, i) => {
    const w = 200 + (i % 4) * 50;
    const h = 200 + ((i + 2) % 3) * 50;
    return {
      id: i + 1,
      name: KITTEN_NAMES[i % KITTEN_NAMES.length],
      width: w,
      height: h,
      url: `https://picsum.photos/seed/kitten${i + 1}/${w}/${h}`,
    };
  });
}

