import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  inject,
  input,
  output,
  signal,
  viewChild,
} from "@angular/core";
import { moduleMetadata, type Meta, type StoryObj } from "@storybook/angular";

import { UIButton } from "../button/button.component";
import { PopoverService } from "./popover.service";
import { PopoverRef, type UIPopoverContent } from "./popover.types";

// ── Popover content components ─────────────────────────────────────

/** Simple tooltip-style content. */
@Component({
  selector: "ui-story-tooltip-content",
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  styles: [
    `
      :host {
        display: block;
        padding: 0.75rem 1rem;
        max-width: 18rem;
      }
      .tooltip-title {
        margin: 0 0 0.25rem;
        font-size: 0.8125rem;
        font-weight: 600;
      }
      .tooltip-body {
        margin: 0;
        font-size: 0.75rem;
        line-height: 1.5;
        opacity: 0.75;
      }
    `,
  ],
  template: `
    <p class="tooltip-title">{{ title() }}</p>
    <p class="tooltip-body">{{ body() }}</p>
  `,
})
class StoryTooltipContent implements UIPopoverContent {
  readonly popoverRef = inject(PopoverRef);
  readonly title = input("Keyboard Shortcut");
  readonly body = input("Press ⌘K to open the command palette.");
}

/** Context menu with a list of actions. */
@Component({
  selector: "ui-story-context-menu",
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  styles: [
    `
      :host {
        display: block;
      }
      .menu-list {
        list-style: none;
        margin: 0;
        padding: 0.25rem 0;
        min-width: 10rem;
      }
      .menu-item {
        padding: 0.5rem 1rem;
        font-size: 0.8125rem;
        cursor: pointer;
        border: none;
        background: none;
        width: 100%;
        text-align: left;
        color: inherit;
        border-radius: 0;
      }
      .menu-item:hover {
        background: var(--theredhead-primary, #4f46e5);
        color: #fff;
      }
      .menu-separator {
        height: 1px;
        background: var(--theredhead-outline-variant, #d7dce2);
        margin: 0.25rem 0;
      }
    `,
  ],
  template: `
    <ul class="menu-list" role="menu">
      @for (item of items(); track item.label) {
        @if (item.separator) {
          <li class="menu-separator" role="separator"></li>
        }
        <li>
