}

// ── Demo: With Filter (auto-inferred) ────────────────────────────────

@Component({
  selector: "ui-mdv-filter-demo",
  standalone: true,
  imports: [UIMasterDetailView, UITemplateColumn, UIAvatar],
  changeDetection: ChangeDetectionStrategy.OnPush,
  styles: [
    `
      :host {
        display: block;
        height: 520px;
        border: 1px solid var(--ui-border, #d7dce2);
        border-radius: 6px;
        overflow: hidden;
      }
