      }
    `,
  ],
  template: `
    <ui-master-detail-view
      [treeDatasource]="treeDatasource"
      [treeDisplayWith]="displayWith"
      [showFilter]="true"
      title="Organization"
      placeholder="Select a person to view their profile"
