const meta: Meta = {
  title: "@Theredhead/UI Blocks/Master Detail View",
  tags: ["autodocs"],
  parameters: {
    docs: {
      description: {
        component:
          "A master-detail layout combining a `<ui-table-view>` or `<ui-tree-view>` " +
