  selector: "ui-dp-iso-demo",
  standalone: true,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [UIDatePicker, DatePipe],
  template: `
    <ui-date-picker
      [(value)]="selected"
      format="yyyy-MM-dd"
      ariaLabel="ISO date"
    />
    <pre class="story-output">
Selected: {{ selected() | date: "fullDate" }}</pre
    >
  `,
  styles: [
