  <ui-dialog-body>
    <p>Dialog body content goes here.</p>
  </ui-dialog-body>
  <ui-dialog-footer>
    <ui-button variant="outlined" (click)="showDialog.set(false)">Cancel</ui-button>
    <ui-button (click)="showDialog.set(false)">OK</ui-button>
  </ui-dialog-footer>
</ui-dialog>

<!-- readonly showDialog = signal(false); -->`,
