import { Meta, StoryObj, moduleMetadata } from "@storybook/angular";
import { Component, ChangeDetectionStrategy } from "@angular/core";

import { UIRepeater } from "./repeater.component";
import { ArrayDatasource } from "../table-view/datasources/array-datasource";

/* ── demo data ────────────────────────────────────────────────── */

interface Kitten {
  id: number;
  name: string;
  width: number;
  height: number;
  url: string;
}

const KITTEN_NAMES = [
  "Whiskers",
  "Mittens",
  "Shadow",
  "Pumpkin",
  "Luna",
  "Simba",
  "Mochi",
  "Cleo",
  "Ginger",
  "Felix",
  "Nala",
  "Oliver",
];

function buildKittens(count = 12): Kitten[] {
  return Array.from({ length: count }, (_, i) => {
    const w = 200 + (i % 4) * 50;
    const h = 200 + ((i + 2) % 3) * 50;
    return {
      id: i + 1,
      name: KITTEN_NAMES[i % KITTEN_NAMES.length],
      width: w,
      height: h,
      url: `https://picsum.photos/seed/kitten${i + 1}/${w}/${h}`,
    };
  });
}

const KITTENS = buildKittens();

/* ── wrapper components ───────────────────────────────────────── */

@Component({
  selector: "ui-repeater-grid-demo",
  standalone: true,
  imports: [UIRepeater],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <ui-repeater [datasource]="ds">
      <ng-template let-kitten let-i="index">
        <figure class="card">
          <img
            [src]="kitten.url"
            [alt]="kitten.name"
            loading="lazy"
            width="200"
            height="200"
          />
          <figcaption>#{{ i + 1 }} {{ kitten.name }}</figcaption>
        </figure>
      </ng-template>
    </ui-repeater>
  `,
  styles: `
    :host {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
      gap: 16px;
      padding: 16px;
    }
    .card {
      margin: 0;
      border-radius: 8px;
      overflow: hidden;
      background: var(--theredhead-surface, #fff);
      box-shadow: 0 1px 4px rgba(0, 0, 0, 0.12);
    }
    .card img {
      display: block;
      width: 100%;
      height: 200px;
      object-fit: cover;
    }
    .card figcaption {
      padding: 8px 12px;
      font:
        500 0.875rem/1.4 system-ui,
        sans-serif;
      color: var(--theredhead-on-surface, #333);
    }
  `,
})
class RepeaterGridDemo {
  public readonly ds = new ArrayDatasource(KITTENS);
}

