import {
  ChangeDetectionStrategy,
  Component,
  input,
  output,
} from "@angular/core";

/** A single item in the breadcrumb trail. */
export interface BreadcrumbItem {
  /** Display label. */
  readonly label: string;
  /** Optional route or URL. When absent, the item is non-clickable. */
  readonly url?: string;
  /** Optional icon identifier. */
  readonly icon?: string;
}

/** Visual style for the breadcrumb trail. */
export type BreadcrumbVariant = "link" | "button";

/**
 * A navigation breadcrumb trail.
 *
 * @example
 * ```html
 * <ui-breadcrumb [items]="[
 *   { label: 'Home', url: '/' },
 *   { label: 'Products', url: '/products' },
 *   { label: 'Widget' }
 * ]" />
 * ```
 */
@Component({
  selector: "ui-breadcrumb",
  standalone: true,
  templateUrl: "./breadcrumb.component.html",
  styleUrl: "./breadcrumb.component.scss",
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    class: "ui-breadcrumb",
    "[class.ui-breadcrumb--button]": "variant() === 'button'",
  },
})
export class UIBreadcrumb {
  /** The breadcrumb items to display. */
  public readonly items = input.required<readonly BreadcrumbItem[]>();

  /** Visual style: `link` (default) renders anchors, `button` renders styled buttons with chevron separators. */
  public readonly variant = input<BreadcrumbVariant>("link");

  /** Separator character between items. Only used in `link` variant. */
  public readonly separator = input("/");

  /** Accessible label for the nav element. */
  public readonly ariaLabel = input("Breadcrumb");

  /** Emitted when a breadcrumb item is clicked. */
  public readonly itemClicked = output<BreadcrumbItem>();

  /** @internal — handle click on a breadcrumb item. */
  protected onItemClick(
    event: Event,
    item: BreadcrumbItem,
    isLast: boolean,
  ): void {
    event.preventDefault();
    if (isLast) {
      return;
    }
    this.itemClicked.emit(item);
  }
}

import { ChangeDetectionStrategy, Component, input } from "@angular/core";

export type ButtonVariant = "filled" | "outlined" | "ghost";
export type ButtonSize = "sm" | "md" | "lg";

/**
 * Thin wrapper around a native `<button>` element.
 *
 * Content is projected via `<ng-content>`, and native `(click)`
 * events bubble up naturally — no custom output needed.
 *
 * @example
 * ```html
 * <ui-button variant="outlined" size="sm" (click)="save()">
 *   Save
 * </ui-button>
 * ```
 */
@Component({
  selector: "ui-button",
  standalone: true,
  templateUrl: "./button.component.html",
  styleUrl: "./button.component.scss",
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    class: "ui-button",
    "[class.ui-button--filled]": "variant() === 'filled'",
    "[class.ui-button--outlined]": "variant() === 'outlined'",
    "[class.ui-button--ghost]": "variant() === 'ghost'",
    "[class.ui-button--sm]": "size() === 'sm'",
    "[class.ui-button--md]": "size() === 'md'",
    "[class.ui-button--lg]": "size() === 'lg'",
  },
})
export class UIButton {
  /** Native button type attribute. */
  readonly type = input<"button" | "submit" | "reset">("button");

  /** Visual style variant. */
  readonly variant = input<ButtonVariant>("filled");

  /** Size preset. */
  readonly size = input<ButtonSize>("md");

  /** Whether the button is disabled. */
  readonly disabled = input(false);

  /**
   * Accessible label forwarded to the native `<button>` as `aria-label`.
   *
   * Use this when the button has no visible text content
   * (e.g. icon-only buttons like a close/remove button).
   */
  readonly ariaLabel = input<string | undefined>(undefined);
}

