import {
  ChangeDetectionStrategy,
  Component,
  inject,
  input,
  signal,
} from "@angular/core";
import { FormsModule } from "@angular/forms";

import { UIIcon } from "../../icon/icon.component";
import { UIIcons } from "../../icon/lucide-icons.generated";
import { PopoverRef, type UIPopoverContent } from "../../popover/popover.types";

// ── Result type ────────────────────────────────────────────────────

/**
 * Value emitted by the image dialog popover on apply.
 * `undefined` means the dialog was cancelled.
 */
export interface ImageDialogResult {
  /** The URL of the image. */
  readonly src: string;

  /** The alt text for the image. */
  readonly alt: string;
}

// ── Component ──────────────────────────────────────────────────────

/**
 * Popover content component for inserting an image by URL.
 *
 * Receives an optional initial URL and alt text via inputs and
 * emits an {@link ImageDialogResult} on apply or `undefined` on
 * cancel / dismiss.
 *
 * @internal  Used exclusively by {@link UIRichTextEditor}.
 */
@Component({
  selector: "ui-image-dialog",
  standalone: true,
  imports: [FormsModule, UIIcon],
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: "ui-image-dialog" },
  templateUrl: "./image-dialog.component.html",
  styleUrl: "./image-dialog.component.scss",
})
export class UIImageDialog implements UIPopoverContent<ImageDialogResult> {
  public readonly popoverRef = inject(PopoverRef<ImageDialogResult>);

  /** Pre-filled image URL (set via input by PopoverService). */
  public readonly initialSrc = input<string>("");

  /** Pre-filled alt text (set via input by PopoverService). */
  public readonly initialAlt = input<string>("");

  /** Mutable URL value for the form. @internal */
  public readonly src = signal("");

  /** Mutable alt-text value for the form. @internal */
  public readonly alt = signal("");

  /** @internal */
  public readonly imageIcon = UIIcons.Lucide.Files.ImagePlus;

  public constructor() {
    queueMicrotask(() => {
      this.src.set(this.initialSrc());
      this.alt.set(this.initialAlt());
    });
  }

  /** Apply the image insertion and close the popover with the result. */
  public apply(): void {
    const src = this.src().trim();
    if (!src) return;
    this.popoverRef.close({ src, alt: this.alt().trim() || "" });
  }

  /** Cancel and dismiss the popover without a result. */
  public cancel(): void {
    this.popoverRef.close(undefined);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  input,
  model,
} from "@angular/core";

/**
 * Thin wrapper around a native `<input>` element.
 *
 * Supports two-way binding via {@link value} (`[(value)]`).
 *
 * @example
 * ```html
 * <ui-input type="number" [(value)]="amount" placeholder="Enter amount" />
 * ```
 */
@Component({
  selector: "ui-input",
  standalone: true,
  templateUrl: "./input.component.html",
  styleUrl: "./input.component.scss",
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: "ui-input" },
})
export class UIInput {
  /** Native input type. */
  readonly type = input<"text" | "number" | "date">("text");

  /** Current value (two-way bindable). */
  readonly value = model("");

  /** Placeholder text. */
  readonly placeholder = input("");

  /** Whether the control is disabled. */
  readonly disabled = input(false);

  /**
   * Accessible label forwarded to the native `<input>` as `aria-label`.
   *
   * Required when no visible `<label>` is associated with the control.
   */
  readonly ariaLabel = input<string | undefined>(undefined);

  /** @internal */
  protected onInput(event: Event): void {
    this.value.set((event.target as HTMLInputElement).value);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  inject,
  input,
  signal,
} from "@angular/core";
import { FormsModule } from "@angular/forms";

import { UIIcon } from "../../icon/icon.component";
import { UIIcons } from "../../icon/lucide-icons.generated";
import { PopoverRef, type UIPopoverContent } from "../../popover/popover.types";

// ── Result type ────────────────────────────────────────────────────

/**
 * Value emitted by the link dialog popover on apply.
 * `undefined` means the dialog was cancelled.
 */
export interface LinkDialogResult {
  /** The URL the link should point to. */
  readonly url: string;

  /** The display text for the link. */
  readonly text: string;
}

// ── Component ──────────────────────────────────────────────────────

/**
 * Popover content component for inserting or editing a hyperlink.
 *
 * Receives the initial URL and display-text values via inputs and
 * emits a {@link LinkDialogResult} on apply or `undefined` on
 * cancel / dismiss.
 *
 * @internal  Used exclusively by {@link UIRichTextEditor}.
 */
@Component({
  selector: "ui-link-dialog",
  standalone: true,
  imports: [FormsModule, UIIcon],
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: "ui-link-dialog" },
  templateUrl: "./link-dialog.component.html",
  styleUrl: "./link-dialog.component.scss",
})
export class UILinkDialog implements UIPopoverContent<LinkDialogResult> {
  readonly popoverRef = inject(PopoverRef<LinkDialogResult>);

  /** Pre-filled URL (set via input by PopoverService). */
  readonly initialUrl = input<string>("");

  /** Pre-filled display text (set via input by PopoverService). */
  readonly initialText = input<string>("");

  /** Whether we are editing an existing link (changes button label). */
  readonly editMode = input<boolean>(false);

  /** Mutable URL value for the form. @internal */
  readonly url = signal("");

  /** Mutable display-text value for the form. @internal */
  readonly text = signal("");

  /** @internal */
  readonly linkIcon = UIIcons.Lucide.Text.Link;

  constructor() {
    // Sync initial inputs → mutable signals after inputs resolve.
    // We use a microtask because signal inputs are set after
    // construction by ComponentRef.setInput().
    queueMicrotask(() => {
      this.url.set(this.initialUrl());
      this.text.set(this.initialText());
    });
  }

  /** Apply the link and close the popover with the result. */
  apply(): void {
    const url = this.url().trim();
    if (!url) return;
    this.popoverRef.close({ url, text: this.text().trim() || url });
  }

  /** Cancel and dismiss the popover without a result. */
  cancel(): void {
    this.popoverRef.close(undefined);
  }
}

